var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"끄으으윽…….","JPN":"くうううっ……","ENG":"Nnngh...","TWN":"咳呃呃呃……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L4_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 작전 성공…!","JPN":"モ、モコ。作戦成功だね……！","ENG":"F-Fluffox. Operation's a success...!","TWN":"福、福實，作戰成功…！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"작전 성공은 무슨! 덕분에 마을 주민들이랑 완전 척을 지게 됐잖아요?","JPN":"何が作戦成功ですか！　おかげで村を敵に回してしまったじゃないですか！","ENG":"Success, my butt. Thanks to you, the villagers totally hate our guts now.","TWN":"什麼作戰成功！因為這樣徹底和村民們結仇了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"심지어, 포박된 사이에 생강 맛 사탕을 잔뜩 먹이지 않나…!","JPN":"しかも、縛られた私にめちゃくちゃジンジャーキャンディー食べさせるし……！","ENG":"And while I was tied up, that fox kept stuffing me with ginger candies...!","TWN":"甚至在被綁住的時候，還讓我們吃一堆生薑口味的糖果…！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"시, 시린그라드에 CRF측정 장치 같은 게 있을 수도 있잖아요.","JPN":"シ、シリングラードにCRF測定装置みたいなものがあるかもしれません。","ENG":"Th-there might be a CRF reader here in Ciringrad.","TWN":"錫、錫林格勒也可能有CRF測量裝置之類的東西。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예니카가 S급 카운터인 걸 들켰다면, 마을에는 쉽게 못 들어왔을 거예요.","JPN":"イェニカがS級カウンターだってバレたら、簡単に入らせてくれなかったと思います。","ENG":"If they learned you are a Grade S Counter, we would never have gotten into the village.","TWN":"要是耶妮卡是S級制裁者的事被發現，應該無法輕易進到村裡來。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으으… 입 열때마다 생강 냄새나는 것 좀 봐.","JPN":"うう……口を開けるたびに生姜の匂いがする。","ENG":"Ugh... My breath smells like ginger every time I talk.","TWN":"呃呃…看看我每次開口的時候就有生薑味。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 머스크 향수나 몇 개 챙겨올 걸, 최악.","JPN":"最悪だよ。ムスクの香水でも持ってくればよかった。","ENG":"If I had known, I would have packed a few more bottles of musk perfume. This is the worst.","TWN":"早知道會這樣，就應該帶幾瓶麝香香水，糟糕透頂。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"후우-. 그래서 이제 어떡하죠?","JPN":"ふう……で、これからどうします？","ENG":"Okay, so what now?","TWN":"呼，所以現在要怎麼辦？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"우, 우선 상황을 정리할게요.","JPN":"ま、まず状況を整理しますね。","ENG":"L-let me lay out the situation first.","TWN":"我、我會先整頓情況。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"저희가 시린그라드에 온 이유는… 곧 전 세계에서 벌어질 대균열 이상 현상.","JPN":"私たちがシリングラードに来た理由は……もうすぐ世界に訪れる大亀裂異常現象。","ENG":"We came to Ciringrad... because of the Grand Dimension Crevice anomalies about to hit worldwide.","TWN":"我們之所以來到錫林格勒…是因為很快就會在全世界發生的大峽谷異常現象。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그것이 발생하기 앞서, 피해를 최소화할 물건을 시린그라드에서 챙겨가기 위해서예요.","JPN":"それが発生する前に、被害を最小限に抑えるのに必要なものを入手するためです。","ENG":"Before that happens, we need to pick up something here to minimize the damage.","TWN":"這是為了在事情發生之前，從錫林格勒帶走能讓傷害最小化的東西。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"우, 우선 첫 번째. 검은 이터니움!","JPN":"ま、まず1つ目は、黒いエタニウム！","ENG":"Th-the first item is Dark Eternium!","TWN":"首、首先第一個是黑色永恆之金！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"가능성을 잃고 색이 변질된 이터니움인데, 이게 선로전환기의 불완전함을 보완해줄 거예요.","JPN":"可能性を失って変色したエタニウムですが、これが線路転換器の不完全さを補ってくれます。","ENG":"It's Eternium that lost its possibilities and turned dark. It'll compensate for the Track Switcher's imperfections.","TWN":"雖然是失去可能性，顏色變質的永恆之金，但這應該能彌補線路轉換器的不完善。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"음… 어떤 원리로요?","JPN":"うーん……どういう原理ですか？","ENG":"Hmm... By what mechanism?","TWN":"嗯…是憑藉什麼原理？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"H-huh?","TWN":"什麼？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"자, 잠시만요. 저 알아요.","JPN":"ま、待ってください。知ってますから。","ENG":"J-just a sec. I know this.","TWN":"等、等一下，我知道。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"진짜 알아요…….","JPN":"本当に知ってますから……","ENG":"I really do...","TWN":"真的知道……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"누가 뭐래요?","JPN":"何も言ってませんよ。","ENG":"Who said you didn't?","TWN":"誰說什麼了嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"啊，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"우, 우선 첫 번째. 검은 이터니움!","JPN":"ま、まず1つ目は、黒いエタニウム！","ENG":"Th-the first item is Dark Eternium!","TWN":"首、首先第一個是黑色永恆之金！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…어떤 원리인데요?","JPN":"……どういう原理ですか？","ENG":"So how does it work?","TWN":"…是什麼原理？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"에헤헤…….","JPN":"えへへ……","ENG":"Ehehe...","TWN":"嘿嘿嘿……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"로, 로터스 시니어님이 만든 선로전환기의 프로토타입의 단점은…….","JPN":"ロ、ロータスのシニアさんが作った線路転換器のプロトタイプの短所は……","ENG":"The prototype Track Switcher the Lotus Senior made has a drawback...","TWN":"洛、洛德斯Senior製作的線路轉換器原型缺點是……"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"이터니움이 집적되어 생긴 국소적 에너지 응집이 차원계면을 붕괴시킨다는 점이에요.","JPN":"エタニウムの集積による局所的なエネルギー凝集が、次元界面を崩壊させてしまうというところです。","ENG":"The local energy clumping from concentrated Eternium collapses the dimension surface.","TWN":"永恆之金積累所產生的局部能量凝聚會破壞次元界面。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"분진 입자가 점화원을 통해 폭발하듯, 이터니움에 담긴 가능성이 매개체가 되어 연쇄 작용을 일으키는 셈이죠.","JPN":"粉塵の粒子が点火元によって爆発するように、エタニウムに込められた可能性が媒介になって、連鎖反応を起こすんですね。","ENG":"Like dust particles igniting from a spark, the possibilities inside Eternium act as a medium and cause a chain reaction.","TWN":"就像粉塵粒子透過點火源爆炸一樣，永恆之金帶有的可能性會成為媒介，引發連鎖作用。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그러니까 이터니움처럼 가능성의 산물이면서, 반대 성질을 지닌 물질을 합성해서 안정 효과를 구현하면…….","JPN":"だ、だから、エタニウムみたいな可能性の産物でありながら、反対する性質を持つ物質を合成して安定効果を出せば……","ENG":"S-so if we synthesize a material that is also born of possibility like Eternium but with the opposite property, we can stabilize it...","TWN":"所、所以如果合成像永恆之金一樣，既是可能性的產物，又具有相反性質的物質後實現穩定效果的話……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으음……?","JPN":"うーん……？","ENG":"Mm...?","TWN":"呃嗯……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"쉬, 쉽게 말하면 이터니움이 플러스. 침식된 이터니움이 마이너스.","JPN":"か、簡単に言うと、エタニウムがプラス。侵食されたエタニウムがマイナス。","ENG":"P-put simply, Eternium is positive. And the Corrupted Eternium is negative.","TWN":"簡、簡單來說就是永恆之金為正，被侵蝕的永恆之金為負。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"플러스 마이너스 제로, 예요…!","JPN":"プラスマイナスゼロ、です……！","ENG":"The plus and minus cancel out to zero...!","TWN":"正負為零…！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐야, 엄청 간단하네.","JPN":"なーんだ、簡単じゃん。","ENG":"Wow, that is actually simple.","TWN":"什麼嘛，超簡單的啊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"처음부터 그렇게 말하지. 뭘 그렇게 어렵게 말해요?","JPN":"最初からそう言えばいいのに、説明が難しすぎますよ。","ENG":"You could have just said that from the start. Why make it sound so complicated?","TWN":"一開始就要這樣說，幹嘛說得那麼難？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L17_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예니카 바보래요.","JPN":"イェニカはバカですって。","ENG":"Fluffox says you're being silly.","TWN":"牠說耶妮卡是笨蛋。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹?","JPN":"コン？","ENG":"Arf?","TWN":"汪？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_QM_NULL","text":{"KOREA":"아까부터 무슨 소란인가 싶더니, 여기서 노닥거리기나 하고…….","JPN":"さっきから騒がしいと思ったら、ここからだったのね……","ENG":"I wondered what the racket was. So you are just loafing around in here...","TWN":"我還想說從剛才開始在吵什麼，結果是在這裡閒聊……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_QM_NULL","text":{"KOREA":"너희들. 잡혔다는 자각은 있는 거야?","JPN":"お前たち、捕まってるって自覚あるの？","ENG":"Do you two even grasp that you were captured?","TWN":"妳們有被抓的自覺嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하아… 북방합의체에서 온 녀석들이 붙잡혔다길래 무슨 꿍꿍이인가 싶더니.","JPN":"はあ……北方合意体から来た奴らが捕まったって言うから、何を企んでるのかと思ったけど。","ENG":"*Sigh...* When I heard some Northern Unioners were caught, I wondered what the scheme was.","TWN":"唉…聽說一群來自北方和議會的傢伙被抓了，我還以為是在打什麼算盤。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"설마, 이런 곳에서 한가롭게 수다나 떨고 있을 줄이야.","JPN":"まさかこんなところで呑気におしゃべりしてたとはね。","ENG":"But chatting away without a care in a place like this?","TWN":"沒想到妳們居然在這種地方悠閒地聊天。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗, 펠릭스의 개다!","JPN":"あっ、フェリックスの犬！","ENG":"Ah, it's Felix's dog!","TWN":"啊，是緋莉克絲的狗！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"폭실이는 개가 아니라 여우예요.","JPN":"モコは犬じゃなくて狐です。","ENG":"Fluffox is not a dog. It is a fox.","TWN":"福實不是狗，而是狐狸。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_PRIDE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L34_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"미안하지만, 나탈리아. 흡혈귀가 말한 개는 그 녀석이 아니라…….","JPN":"悪いけど、ナタリア。吸血鬼が言ってる犬はそっちじゃなくて……","ENG":"Sorry, Natalia. The \\"dog\\" the vampire meant was not it...","TWN":"抱歉，但是那塔利亞，吸血鬼說的狗不是那個傢伙……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"아, 아니! 난 펠릭스의 개가 아니야! 애초에 이제 합의체 소속도 아니라고!","JPN":"って、ちょっと！　私はフェリックスの犬じゃないわ！　そもそも、もう合意体所属でもないし！","ENG":"N-no! I am not Felix's dog! I am not even with the Northern Union anymore!","TWN":"不、不是！我不是緋莉克絲的狗！我一開始就不是隸屬和議會！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐래, 네가 입고 있는 합의체 제복은 장식이니?","JPN":"合意体の制服着てるくせに、何言ってるの。","ENG":"Oh really? That Northern Union uniform you are wearing is for show, then?","TWN":"妳在說什麼？那妳身上穿的和議會制服是裝飾嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"한동안 안보인다 싶더니, 천하의 장군께서 이런 시골에 잡혀 있었구나?","JPN":"しばらく見ないなと思ったら、天下の将軍様がこんな田舎で捕まっていたとはね。","ENG":"So the mighty general went missing for a while, only to get nabbed in some backwater village?","TWN":"本來還在想好一陣子不見人影，結果天下無敵的將軍被抓到這種鄉下？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이, 이건… 어쩔 수 없어. 도망칠 때 가지고 나온 여벌이 없다고.","JPN":"こ、これは……仕方なかったのよ。逃げる時、着替えを持って来れなかったから。","ENG":"I-it couldn't be helped. I had no spare clothes when I defected.","TWN":"這、這個…沒辦法，逃跑的時候沒有多的衣服能拿出來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그렇지 않고서야 시린그라드에서 북방군 소속인 걸 티 낼 이유가 없잖아?","JPN":"そうじゃなかったら、わざわざシリングラードで北方軍所属だって分かる格好するわけないじゃん。","ENG":"Otherwise why would I flaunt the Northern Union colors in Ciringrad?","TWN":"不然，沒理由在錫林格勒展現出一副自己是北方軍的樣子吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하, 이번에는 배신자인 척하는 북방의 개 역할이야?","JPN":"はは～ん。今回の設定は裏切り者のふりをする北方の犬かぁ～","ENG":"A-ha. So this time, you're playing the role of a Northern Union dog pretending to be a traitor?","TWN":"啊哈，這次是扮演裝作叛徒的北方的狗嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"충신도 이런 충신이 없네. 정년 이후에 먹을 사료 걱정은 안 해도 되겠는 걸?","JPN":"本当、忠臣の中の忠臣だね。定年後も餌の心配はなさそうでよかったよ。","ENG":"Being loyal to a fault. guess you won't have to worry about not having food to eat after retirement.","TWN":"也沒有像你這樣的忠臣了，應該不用擔心退休後要吃的飼料了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너, 내 말을 들을 생각이 추호도 없구나?","JPN":"お前、私の話聞く気ないわね？","ENG":"You have zero intention of listening to me.","TWN":"看來妳之後也不打算聽我的話啊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"무, 문이… 열렸네요.","JPN":"ド、ドアが……開きましたね。","ENG":"Th-the door... it opened.","TWN":"門、門…打開了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"시간 없으니 따라와.","JPN":"時間がないわ。ついて来なさい。","ENG":"There's no time. Follow me.","TWN":"沒時間了，跟我來吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너희가 어떻게 생각하든, 조용히 빠져나갈 수 있는 건 지금 뿐이니까.","JPN":"お前たちにどう思われようが、静かに抜け出せるのは今しかないから。","ENG":"Believe what you want, but this is our only shot to slip out quietly.","TWN":"不管你們怎麼想，就只有現在能安靜逃脫了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};